# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, url_for
from flask_sqlalchemy import SQLAlchemy
import secrets
import datetime
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///app.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class PasswordReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(64), unique=True, nullable=False)
    created_at = db.Column(db.DateTime, default=datetime.datetime.utcnow)

def send_reset_email(recipient_email, reset_link):
    # Configure these for your SMTP server
    SMTP_SERVER = 'smtp.example.com'
    SMTP_PORT = 587
    SMTP_USERNAME = 'your_username'
    SMTP_PASSWORD = 'your_password'
    FROM_EMAIL = 'noreply@example.com'
    
    subject = 'Password Reset'
    body = f'Click the following link to reset your password: {reset_link}'
    
    msg = MIMEText(body)
    msg['Subject'] = subject
    msg['From'] = FROM_EMAIL
    msg['To'] = recipient_email

    try:
        smtp = smtplib.SMTP(SMTP_SERVER, SMTP_PORT)
        smtp.starttls()
        smtp.login(SMTP_USERNAME, SMTP_PASSWORD)
        smtp.sendmail(FROM_EMAIL, [recipient_email], msg.as_string())
        smtp.quit()
    except Exception as e:
        print(f"Error sending email: {e}")

@app.route('/api/password-reset', methods=['POST'])
def password_reset():
    data = request.get_json()
    email = data.get('email')
    if not email:
        return jsonify({'error': 'Email is required.'}), 400

    token = secrets.token_urlsafe(16)
    reset_request = PasswordReset(email=email, token=token)
    db.session.add(reset_request)
    db.session.commit()

    # Generate a reset URL. You can later create an endpoint that uses this token.
    reset_link = url_for('reset_password_token', token=token, _external=True)
    send_reset_email(email, reset_link)

    return jsonify({'message': 'Password reset link has been sent.'}), 200

@app.route('/reset/<token>', methods=['GET'])
def reset_password_token(token):
    # This endpoint would be used to verify the token and allow user to enter a new password.
    reset_entry = PasswordReset.query.filter_by(token=token).first()
    if not reset_entry:
        return jsonify({'error': 'Invalid or expired token.'}), 400
    return jsonify({'message': 'Token is valid. Proceed with password reset.'}), 200

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)